"""web_login.py — Stitch glass login in a native WebView2 window (pywebview),
shown BEFORE the Flet app when no session exists. The HTML form is bridged to
auth_supabase; on success the session is cached so the Flet app boots straight in.

Returns from run_login():
  {"user": <dict>, "theme": "dark"|"light"}  on successful sign-in
  None                                         user closed the window w/o signing in
  {"unavailable": True}                        pywebview not installed (caller should
                                               fall back to the in-app Flet gate)

Windows deps:  pip install pywebview pythonnet   (Edge WebView2 runtime backend)
"""
import base64
import os
import threading

import auth_supabase as auth

_HTML_B64 = ""


def _version():
    try:
        here = os.path.dirname(os.path.abspath(__file__))
        with open(os.path.join(here, "VERSION"), "r", encoding="utf-8") as f:
            return f.read().strip()
    except Exception:
        return ""


def _html():
    html = base64.b64decode(_HTML_B64).decode("utf-8")
    ver = _version()
    if ver:
        # inject the live version before the main script reads it
        html = html.replace(
            '<script>const VER=',
            '<script>window.__qaVersion="' + ver + '";</script>\n<script>const VER=',
            1)
    return html


class _Api:
    def __init__(self):
        self.result = None
        self.window = None

    def submit(self, p):
        try:
            p = p or {}
            action = p.get("action"); email = p.get("email"); pw = p.get("password")
            name = p.get("name"); theme = p.get("theme")
            if action == "signup":
                ok, msg, user = auth.sign_up(email, pw, name=name or None)
            else:
                ok, msg, user = auth.sign_in(email, pw)
            if user:
                self.result = {"user": user, "theme": theme}
                try:
                    if self.window:
                        threading.Timer(0.15, self.window.destroy).start()
                except Exception:
                    pass
                return {"ok": True}
            return {"ok": bool(ok), "message": msg, "kind": "ok" if ok else "err",
                    "action": action}
        except Exception as ex:
            return {"ok": False, "message": "Something went wrong: %s" % ex, "kind": "err"}

    def forgot(self, p):
        try:
            ok, msg = auth.request_password_reset((p or {}).get("email"))
            return {"ok": bool(ok), "message": msg, "kind": "ok" if ok else "err"}
        except Exception as ex:
            return {"ok": False, "message": str(ex), "kind": "err"}


def run_login(width=1120, height=760, title="QA Studio"):
    try:
        import webview
    except Exception:
        return {"unavailable": True}
    api = _Api()
    try:
        import logging
        logging.getLogger("pywebview").setLevel(logging.CRITICAL)
    except Exception:
        pass
    # centre on the primary screen (pywebview otherwise lets the OS place it,
    # which on Windows can drop it low/left)
    _x = _y = None
    try:
        import ctypes
        try:
            ctypes.windll.shcore.SetProcessDpiAwareness(1)
        except Exception:
            pass
        _u = ctypes.windll.user32
        _sw, _sh = _u.GetSystemMetrics(0), _u.GetSystemMetrics(1)
        _x = max(0, (_sw - int(width)) // 2)
        _y = max(0, (_sh - int(height)) // 2)
    except Exception:
        _x = _y = None

    # window + taskbar icon (else it shows the generic python.exe icon)
    _icon = None
    try:
        _here = os.path.dirname(os.path.abspath(__file__))
        for _n in ("app.ico", "app.png"):
            _p = os.path.join(_here, _n)
            if os.path.exists(_p):
                _icon = _p
                break
    except Exception:
        _icon = None

    _cw = dict(title=title, html=_html(), js_api=api,
               width=int(width), height=int(height), min_size=(980, 660))
    if _x is not None:
        _cw["x"], _cw["y"] = _x, _y
    try:
        api.window = webview.create_window(**_cw)
    except Exception:
        # some backends reject x/y — retry centred-less
        _cw.pop("x", None); _cw.pop("y", None)
        try:
            api.window = webview.create_window(**_cw)
        except Exception:
            return {"unavailable": True}

    def _start():
        # icon= is pywebview >=5; fall back gracefully on older builds/backends
        try:
            if _icon:
                webview.start(gui="edgechromium", icon=_icon)
                return
        except TypeError:
            pass
        webview.start(gui="edgechromium")

    try:
        _start()
    except Exception:
        try:
            webview.start()
        except Exception:
            return {"unavailable": True}
    return api.result
